// Parentz Screen Importer - UI thread handles base64 decoding

const SCREENS = [
  { label: "Buddy Pods - List", data: "data:image/png;base64," },
  { label: "Art Class Pod - Chat", data: "data:image/png;base64," },
  { label: "Art Class Pod - Chat (Playground Playdate)", data: "data:image/png;base64," },
  { label: "Art Class Group - Detail", data: "data:image/png;base64," },
  { label: "Art Class Activities", data: "data:image/png;base64," },
  { label: "Art Class Group - Dropdown Menu", data: "data:image/png;base64," },
  { label: "Kids Lounge - Main", data: "data:image/png;base64," },
  { label: "Leave Art Class Group - Confirmation", data: "data:image/png;base64," },
  { label: "Edit Pod Details", data: "data:image/png;base64," },
  { label: "Delete Art Class Group - Confirmation", data: "data:image/png;base64," },
  { label: "Manage Members", data: "data:image/png;base64," },
  { label: "Invite Members", data: "data:image/png;base64," },
  { label: "Create Buddy Pod", data: "data:image/png;base64," },
  { label: "Invite Members - Create Pod", data: "data:image/png;base64," },
];

const FRAME_W = 390;
const FRAME_H = 844;
const GAP = 48;

figma.showUI(__html__, { width: 380, height: 180 });

const frames = [];
let doneCount = 0;

async function createFrames() {
  await figma.loadFontAsync({ family: 'Inter', style: 'Medium' });

  for (let i = 0; i < SCREENS.length; i++) {
    const x = i * (FRAME_W + GAP);

    const txt = figma.createText();
    txt.fontName = { family: 'Inter', style: 'Medium' };
    txt.characters = SCREENS[i].label;
    txt.fontSize = 13;
    txt.fills = [{ type: 'SOLID', color: { r: 0.3, g: 0.3, b: 0.3 } }];
    txt.x = x; txt.y = 0;
    txt.resize(FRAME_W, 32);

    const frame = figma.createFrame();
    frame.name = SCREENS[i].label;
    frame.resize(FRAME_W, FRAME_H);
    frame.x = x; frame.y = 48;
    frame.fills = [{ type: 'SOLID', color: { r: 0.94, g: 0.94, b: 0.94 } }];
    frames.push(frame);
  }

  figma.viewport.scrollAndZoomIntoView(frames);

  figma.ui.postMessage({
    type: 'decode',
    screens: SCREENS.map((s, i) => ({ index: i, label: s.label, data: s.data }))
  });
}

figma.ui.onmessage = (msg) => {
  if (msg.type === 'imageBytes') {
    const { index, bytes } = msg;
    try {
      const img = figma.createImage(new Uint8Array(bytes));
      frames[index].fills = [{ type: 'IMAGE', imageHash: img.hash, scaleMode: 'FILL' }];
      doneCount++;
      figma.ui.postMessage({ type: 'progress', done: doneCount, total: SCREENS.length });
      if (doneCount === SCREENS.length) {
        setTimeout(() => figma.closePlugin(`Done! ${doneCount}/${SCREENS.length} screens.`), 1500);
      }
    } catch(e) {
      figma.ui.postMessage({ type: 'error', label: frames[index] ? frames[index].name : index, msg: e.message });
    }
  }
};

createFrames().catch(err => figma.closePlugin('Error: ' + err.message));
